3_real_world_example.code:
function createCounter() {
  let count = 0; // Private variable

  return function increment() { 
    // Inner function forms a closure over 'count'
    count++;
    return count;
  };
}

// Outer function runs and finishes. Returns the inner function.
const myCounter = createCounter(); 

// myCounter still remembers 'count'!
console.log(myCounter()); // 1
console.log(myCounter()); // 2

6_edge_case.code:
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100); 
  // Prints: 3, 3, 3 (because 'i' is shared across all closures)
}

//  Fix: Use 'let' which creates a fresh block-scoped variable per iteration.
for (let j = 0; j < 3; j++) {
  setTimeout(() => console.log(j), 100); 
  // Prints: 0, 1, 2
}
